content.text:
Rekursiv funksiya adi funksiyadan fərqlənmir, ancaq özünü çağırır. Aşağıdakı sintaksisə malikdir:
return_type function_name(parameters) {
  // Əsas hal
  if(condition) return value;
  // Rekursiv çağırış
  return function_name(modified_parameters);
}
Əsas halın olması vacibdir, əks halda funksiya sonsuz dövrə düşə bilər.

content.code:
#include <iostream>

int factorial(int n) {
  if(n <= 1) return 1;
  return n * factorial(n - 1);
}

int main() {
  int number = 5;
  int result = factorial(number);
  std::cout << "Factorial of " << number << " is " << result << std::endl;
  return 0;
}
// Output:
// Factorial of 5 is 120

#include <iostream>

int fibonacci(int n) {
  if(n <= 1) return n;
  return fibonacci(n - 1) + fibonacci(n - 2);
}

int main() {
  int number = 6;
  int result = fibonacci(number);
  std::cout << "Fibonacci of " << number << " is " << result << std::endl;
  return 0;
}
// Output:
// Fibonacci of 6 is 8

#include <iostream>

int sum_to_n(int n) {
  if(n <= 0) return 0;
  return n + sum_to_n(n - 1);
}

int main() {
  int number = 4;
  int result = sum_to_n(number);
  std::cout << "Sum up to " << number << " is " << result << std::endl;
  return 0;
}
// Output:
// Sum up to 4 is 10

